CREATE TABLE `ChemicalReaction` (
  `id` int NOT NULL AUTO_INCREMENT,
  `firstElement` int NOT NULL,
  `secondElement` int NOT NULL,
  `productName` varchar(255) NOT NULL,
  `productInfo` text,
  `reactionType` enum('Combination','Decomposition','Single Replacement','Double Replacement','Combustion','No Reaction') NOT NULL DEFAULT 'No Reaction',
  `hazardLevel` enum('Low','Moderate','High','Extreme','No Hazard') NOT NULL DEFAULT 'No Hazard',
  `hazardType` enum('Flammable','Explosive','Corrosive','Toxic','Irritant','Oxidizing','Environmental','No Hazard') NOT NULL DEFAULT 'No Hazard',
  `hazardInfo` text,
  PRIMARY KEY (`id`),
  KEY `fk_firstElement` (`firstElement`),
  KEY `fk_secondElement` (`secondElement`),
  CONSTRAINT `fk_firstElement` FOREIGN KEY (`firstElement`) REFERENCES `PeriodicTable` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_secondElement` FOREIGN KEY (`secondElement`) REFERENCES `PeriodicTable` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=151 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
