INSERT INTO `ChemicalReaction` VALUES (1,1,8,'H2O','Water - Colorless, tasteless liquid at room temperature. Essential for life, exhibits hydrogen bonding, high specific heat, and universal solvent properties.','Combination','No Hazard','No Hazard','Generally safe under normal conditions, but can cause drowning in large quantities.'),(2,6,8,'CO2','Carbon Dioxide - Colorless gas with faint acidic taste. Non-flammable, slightly soluble in water forming carbonic acid, used in beverages and fire extinguishers.','Combination','Low','Environmental','High concentrations can displace oxygen and cause suffocation. Mild asphyxiant risk.'),(3,7,2,'N2O','Nitrous Oxide - Colorless, slightly sweet gas. Known as laughing gas, used as anesthetic and oxidizer in combustion reactions.','Combination','Moderate','Oxidizing','Supports combustion, can cause oxygen displacement in enclosed spaces, inhalation at high concentration may cause dizziness or unconsciousness.'),(4,11,17,'NaCl','Sodium Chloride - White crystalline solid, soluble in water, salty taste, used as table salt and in industrial chemical processes.','Combination','No Hazard','No Hazard','Safe under normal use. Excessive ingestion can cause hypertension or other health issues.'),(5,12,17,'MgCl2','Magnesium Chloride - White crystalline solid, highly soluble in water. Used in de-icing, dust control, and as a source of magnesium.','Combination','Moderate','Irritant','May irritate skin, eyes, and respiratory tract upon dust exposure. Hygroscopic and absorbs moisture from air.'),(6,8,16,'O2','Oxygen Gas - Colorless, odorless gas, essential for respiration. Supports combustion.','Decomposition','High','Oxidizing','Supports fire and combustion, highly reactive with flammable materials.'),(7,8,9,'OF2','Oxygen Difluoride - Pale yellow gas, pungent odor, highly reactive and toxic. Strong oxidizer, reacts violently with water and organics.','Combination','Extreme','Corrosive','Highly toxic if inhaled, can cause severe burns on contact with skin or mucous membranes, reacts explosively with organics.'),(8,1,17,'HCl','Hydrochloric Acid - Colorless to slightly yellow corrosive liquid, pungent odor, strong acid used in industrial and laboratory applications.','Combination','High','Corrosive','Severe burns on contact, inhalation may damage respiratory tract. Reacts violently with bases and metals.'),(9,1,6,'CH4','Methane - Colorless, odorless gas, highly flammable. Major component of natural gas.','Combination','High','Flammable','Highly flammable, forms explosive mixtures with air, inhalation in high concentration may cause asphyxiation.'),(10,6,8,'CO','Carbon Monoxide - Colorless, odorless gas, extremely toxic. Formed by incomplete combustion of carbon.','Combination','Extreme','Toxic','Binds hemoglobin, preventing oxygen transport. Can be fatal even at low concentrations.'),(11,12,16,'CO2','Carbon Dioxide - Colorless, odorless gas, slightly acidic in water. Used in carbonated beverages, fire suppression, and refrigeration.','Combustion','Low','Environmental','Non-flammable, displaces oxygen at high concentrations causing suffocation risk.'),(12,11,8,'Na2O','Sodium Oxide - White crystalline solid, reacts violently with water to form sodium hydroxide.','Combination','High','Corrosive','Causes severe burns, reacts exothermically with water, may ignite organic materials.'),(13,20,8,'CaO','Calcium Oxide - White solid (quicklime), highly reactive with water forming calcium hydroxide (slaked lime).','Combination','High','Corrosive','Can cause severe burns upon contact with skin or eyes, reacts vigorously with water producing heat.'),(14,12,16,'MgO','Magnesium Oxide - White powder, high melting point, used in refractory materials.','Combination','Moderate','Irritant','Dust can irritate eyes and respiratory system, generally safe in bulk form.'),(15,7,8,'NO','Nitric Oxide - Colorless gas, reacts with oxygen to form nitrogen dioxide. Used in industrial and medical applications.','Combination','Moderate','Oxidizing','Supports combustion, can form toxic nitrogen dioxide in air, inhalation hazardous.'),(16,7,8,'NO2','Nitrogen Dioxide - Reddish-brown gas, pungent, toxic, contributes to smog formation.','Combination','High','Toxic','Severely irritates lungs and eyes, can cause pulmonary edema and chronic respiratory issues.'),(17,1,16,'H2O2','Hydrogen Peroxide - Colorless liquid, strong oxidizer, used as bleach and disinfectant.','Combination','High','Oxidizing','Causes burns on contact, may decompose violently under heat or contamination.'),(18,6,1,'CH4','Methane - Colorless, odorless flammable gas, main component of natural gas.','Combination','High','Flammable','Highly flammable, explosive when mixed with air, asphyxiant in high concentrations.'),(19,15,16,'P2O5','Phosphorus Pentoxide - White solid, highly hygroscopic, reacts violently with water to form phosphoric acid.','Combination','Extreme','Corrosive','Severe burns on contact, generates heat and acidic mist upon contact with water, irritates respiratory tract.'),(20,16,1,'H2S','Hydrogen Sulfide - Colorless gas with rotten egg odor, toxic, flammable.','Combination','Extreme','Toxic','Highly toxic even at low concentrations, can cause respiratory failure, flammable and explosive in air.'),(21,3,8,'LiO','Lithium + Oxygen reaction product. Solid oxide often used in ceramics.','Combination','Moderate','Oxidizing','Oxidizes easily, dust may irritate.'),(22,4,8,'BeO','Beryllium Oxide - high melting solid, used in electronics.','Combination','High','Irritant','Dust and fumes can irritate eyes/skin.'),(23,5,9,'BF','Boron Fluoride reaction product (fictional simple oxide representation).','Combination','High','Corrosive','Irritating to mucous membranes.'),(24,10,2,'NeHe','Neon + Helium hypothetical noble gas interaction.','No Reaction','No Hazard','No Hazard','Noble gases do not react under normal conditions.'),(25,11,16,'NaS','Sodium + Sulfur reaction, used in some sulfide materials.','Combination','Moderate','No Hazard',